css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #080010; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; border-bottom: 1px solid rgba(139,92,246,0.2); position: sticky; top: 0; background: rgba(8,0,16,0.9); backdrop-filter: blur(20px); z-index: 100; }
.logo { font-size: 22px; font-weight: 900; background: linear-gradient(135deg, #a855f7, #ec4899); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.nav-right { display: flex; gap: 12px; align-items: center; }
.wallet-info { padding: 8px 14px; border-radius: 10px; border: 1px solid rgba(139,92,246,0.3); background: rgba(139,92,246,0.08); color: #c084fc; font-size: 13px; font-family: monospace; }
.connect-btn { padding: 10px 20px; border-radius: 10px; border: none; background: linear-gradient(135deg, #7c3aed, #ec4899); color: white; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 72px); }
.collection-badge { display: inline-block; color: #a855f7; font-size: 13px; font-weight: 700; letter-spacing: 2px; margin-bottom: 20px; }
h1 { font-size: 72px; font-weight: 900; line-height: 1; letter-spacing: -3px; margin-bottom: 20px; } h1 span { background: linear-gradient(135deg, #a855f7, #ec4899); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.hero-left p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 28px; max-width: 460px; }
.hero-stats { display: flex; gap: 24px; margin-bottom: 32px; }
.hs { padding: 14px 18px; border-radius: 14px; background: rgba(255,255,255,0.04); border: 1px solid rgba(139,92,246,0.2); text-align: center; } .hs strong { display: block; font-size: 22px; font-weight: 900; color: #c084fc; } .hs span { color: #6b7280; font-size: 12px; }
.hero-btns { display: flex; gap: 14px; }
.btn-mint { padding: 16px 32px; border-radius: 16px; border: none; background: linear-gradient(135deg, #7c3aed, #ec4899); color: white; font-weight: 800; font-size: 15px; cursor: pointer; box-shadow: 0 20px 40px rgba(124,58,237,0.35); }
.btn-explore { padding: 16px 28px; border-radius: 16px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.nft-showcase { display: flex; flex-direction: column; gap: 14px; }
.nft-main { width: 100%; aspect-ratio: 1; border-radius: 24px; background: linear-gradient(135deg, #1a0a2e, #2d1b69, #7c3aed); display: flex; align-items: center; justify-content: center; font-size: 96px; position: relative; border: 1px solid rgba(139,92,246,0.4); box-shadow: 0 20px 60px rgba(124,58,237,0.25); }
.nft-label { position: absolute; bottom: 16px; left: 16px; right: 16px; background: rgba(0,0,0,0.7); backdrop-filter: blur(10px); border-radius: 12px; padding: 10px 14px; display: flex; justify-content: space-between; align-items: center; font-size: 14px; font-weight: 700; } .nft-label span { color: #c084fc; }
.nft-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 12px; }
.nft-sm { aspect-ratio: 1; border-radius: 14px; background: linear-gradient(135deg, #1a0a2e, #2d1b69); display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 6px; font-size: 28px; border: 1px solid rgba(139,92,246,0.25); position: relative; }
.nft-sm-label { font-size: 10px; color: #9ca3af; font-weight: 600; }
.collection { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.07); }
.coll-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 32px; }
.coll-header h2 { font-size: 40px; font-weight: 800; }
.coll-filters { display: flex; gap: 8px; }
.cf { padding: 10px 20px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: #6b7280; font-size: 13px; font-weight: 600; cursor: pointer; } .cf.active { background: linear-gradient(135deg, #7c3aed, #ec4899); border-color: transparent; color: white; }
.nft-grid-full { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 16px; }
.nft-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(139,92,246,0.2); border-radius: 18px; overflow: hidden; cursor: pointer; transition: all 0.2s; } .nft-card:hover { transform: translateY(-4px); border-color: rgba(168,85,247,0.5); box-shadow: 0 12px 30px rgba(124,58,237,0.2); }
.nc-img { height: 180px; display: flex; align-items: center; justify-content: center; font-size: 60px; }
.nc-info { padding: 12px; } .nc-name { font-size: 14px; font-weight: 700; margin-bottom: 6px; } .nc-price { display: flex; justify-content: space-between; align-items: center; } .nc-eth { color: #c084fc; font-weight: 700; font-size: 15px; }
.nc-rarity { padding: 3px 8px; border-radius: 6px; font-size: 10px; font-weight: 800; }
.rare { background: rgba(59,130,246,0.2); color: #60a5fa; }
.epic { background: rgba(139,92,246,0.2); color: #a78bfa; }
.legendary { background: rgba(234,179,8,0.2); color: #fde68a; }

