const nfts = [
  {id:'#0001',emoji:'🎭',price:'8.2Ξ',rarity:'legendary',bg:'#1a0a2e,#7c3aed'},
  {id:'#0042',emoji:'🤖',price:'3.1Ξ',rarity:'epic',bg:'#0a1a2e,#1d4ed8'},
  {id:'#0128',emoji:'👾',price:'1.8Ξ',rarity:'rare',bg:'#0a2e1a,#166534'},
  {id:'#0256',emoji:'🦄',price:'5.4Ξ',rarity:'legendary',bg:'#2e0a1a,#9f1239'},
  {id:'#0512',emoji:'🐉',price:'12.0Ξ',rarity:'legendary',bg:'#1a1a0a,#854d0e'},
  {id:'#0777',emoji:'🧙',price:'2.2Ξ',rarity:'epic',bg:'#1a0a2e,#4c1d95'},
  {id:'#0888',emoji:'🦊',price:'0.9Ξ',rarity:'rare',bg:'#2e1a0a,#c2410c'},
  {id:'#0999',emoji:'🌊',price:'1.5Ξ',rarity:'rare',bg:'#0a1a2e,#075985'}
];
let currentFilter = 'all';
function renderNFTs() {
  const visible = currentFilter === 'all' ? nfts : nfts.filter(n => n.rarity === currentFilter);
  document.getElementById('nft-grid').innerHTML = visible.map(n => `
    <div class='nft-card'>
      <div class='nc-img' style='background:linear-gradient(135deg,#${n.bg})'>${n.emoji}</div>
      <div class='nc-info'>
        <div class='nc-name'>CryptoVerse ${n.id}</div>
        <div class='nc-price'><span class='nc-eth'>${n.price}</span><span class='nc-rarity ${n.rarity}'>${n.rarity.toUpperCase()}</span></div>
      </div>
    </div>
  `).join('');
}
function filterNFT(f, btn) { currentFilter = f; document.querySelectorAll('.cf').forEach(b => b.classList.remove('active')); btn.classList.add('active'); renderNFTs(); }
renderNFTs();
document.querySelector('.btn-mint').addEventListener('click', function() { this.textContent = '✓ Mint Başarılı!'; this.style.background = '#22c55e'; setTimeout(() => { this.textContent = '⚡ Mint Et — 0.08Ξ'; this.style.background = ''; }, 2000); });
